package logging

import (
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
)

// Init opens ~/.agentlens/debug.log for append and installs a slog text
// handler as the default. Must be called once from main before any logging.
func Init(debug bool) error {
	home, err := os.UserHomeDir()
	if err != nil {
		return fmt.Errorf("user home: %w", err)
	}
	dir := filepath.Join(home, ".agentlens")
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("mkdir %s: %w", dir, err)
	}
	path := filepath.Join(dir, "debug.log")
	f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644)
	if err != nil {
		return fmt.Errorf("open log: %w", err)
	}
	level := slog.LevelInfo
	if debug {
		level = slog.LevelDebug
	}
	handler := slog.NewTextHandler(f, &slog.HandlerOptions{Level: level})
	slog.SetDefault(slog.New(handler))
	return nil
}

package tui

import "github.com/charmbracelet/lipgloss"

// Styles bundles the shared lipgloss styles derived from a Theme.
//
// TODO(phase-4+): expand as screens are built.
type Styles struct {
	App   lipgloss.Style
	Title lipgloss.Style
	Hint  lipgloss.Style
	Error lipgloss.Style
}

// NewStyles builds a Styles from a Theme.
func NewStyles(t Theme) Styles {
	return Styles{
		App:   lipgloss.NewStyle().Foreground(t.Foreground),
		Title: lipgloss.NewStyle().Foreground(t.Accent).Bold(true),
		Hint:  lipgloss.NewStyle().Foreground(t.Muted),
		Error: lipgloss.NewStyle().Foreground(t.Error),
	}
}

package tui

import "github.com/charmbracelet/lipgloss"

// Theme holds the color palette used across the TUI. All styles must reference
// a Theme field — no hardcoded colors elsewhere.
//
// TODO(phase-6): add Nord and Dracula variants; wire selection via settings.
type Theme struct {
	Name       string
	Background lipgloss.Color
	Foreground lipgloss.Color
	Accent     lipgloss.Color
	Muted      lipgloss.Color
	TokenBar   lipgloss.Color
	TokenEmpty lipgloss.Color
	Error      lipgloss.Color
}

// CatppuccinMocha is the default theme.
func CatppuccinMocha() Theme {
	return Theme{
		Name:       "catppuccin-mocha",
		Background: lipgloss.Color("#1e1e2e"),
		Foreground: lipgloss.Color("#cdd6f4"),
		Accent:     lipgloss.Color("#89b4fa"),
		Muted:      lipgloss.Color("#6c7086"),
		TokenBar:   lipgloss.Color("#a6e3a1"),
		TokenEmpty: lipgloss.Color("#313244"),
		Error:      lipgloss.Color("#f38ba8"),
	}
}

