package tui

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/lipgloss"
)

// truncate shortens s to at most max runes. If truncation occurs the last
// character is replaced with an ellipsis (…). If max == 1 it always returns
// "…".
func truncate(s string, max int) string {
	runes := []rune(s)
	if len(runes) <= max {
		return s
	}
	if max <= 1 {
		return "…"
	}
	return string(runes[:max-1]) + "…"
}

// padRight pads s with spaces on the right until it reaches width. Strings
// already at or over width are returned unchanged.
func padRight(s string, width int) string {
	runes := []rune(s)
	if len(runes) >= width {
		return s
	}
	return s + strings.Repeat(" ", width-len(runes))
}

// countLabel formats n with the singular label, pluralising with an "s" when
// n != 1. E.g. countLabel(1, "session") → "1 session", countLabel(3, "session") → "3 sessions".
func countLabel(n int, singular string) string {
	if n == 1 {
		return fmt.Sprintf("%d %s", n, singular)
	}
	return fmt.Sprintf("%d %ss", n, singular)
}

// kbd renders a keyboard hint with a styled key and description.
func kbd(k, desc string) string {
	return keyStyle.Render(k) + " " + descStyle.Render(desc)
}

// joinHints joins multiple hint strings with a dim separator.
func joinHints(hints ...string) string {
	sep := dimStyle.Render("  ·  ")
	return strings.Join(hints, sep)
}

// hRule returns a full-width horizontal rule of the given width.
func hRule(width int) string {
	return dimStyle.Render(strings.Repeat("─", width))
}

// pill renders a small label badge with given foreground and background colors.
func pill(label string, fg, bg lipgloss.TerminalColor) string {
	return lipgloss.NewStyle().
		Foreground(fg).
		Background(bg).
		Padding(0, 1).
		Render(label)
}

// subviewHeader renders a chrome header row with title, optional breadcrumbs,
// and a right-aligned "esc back" hint, all on a mantle background.
func subviewHeader(width int, title string, crumbs []string) string {
	left := lipgloss.NewStyle().Foreground(colMauve).Bold(true).Render("◆ " + title)
	if len(crumbs) > 0 {
		sep := dimStyle.Render(" › ")
		crumbText := strings.Join(mapStyle(crumbs, subtitleStyle), sep)
		left = left + "  " + crumbText
	}
	right := dimStyle.Render("esc ") + keyStyle.Render("back")
	gap := width - lipgloss.Width(left) - lipgloss.Width(right) - 2
	if gap < 1 {
		gap = 1
	}
	row := left + strings.Repeat(" ", gap) + right
	return lipgloss.NewStyle().Width(width).Padding(0, 1).Background(colMantle).Render(row)
}

// subviewFooter renders a chrome footer row with joined hints on a mantle background.
func subviewFooter(width int, hints ...string) string {
	return lipgloss.NewStyle().Width(width).Padding(0, 1).Background(colMantle).Render(joinHints(hints...))
}

// mapStyle applies style to each string in the slice and returns the results.
func mapStyle(in []string, style lipgloss.Style) []string {
	out := make([]string, len(in))
	for i, s := range in {
		out[i] = style.Render(s)
	}
	return out
}

package tui

import "github.com/charmbracelet/lipgloss"

// Catppuccin Mocha (dark) / Latte (light) adaptive color palette.
// Colors are added here as screens are built.
var (
	colBase     = lipgloss.AdaptiveColor{Dark: "#1e1e2e", Light: "#eff1f5"}
	colMantle   = lipgloss.AdaptiveColor{Dark: "#181825", Light: "#e6e9ef"}
	colSurface0 = lipgloss.AdaptiveColor{Dark: "#313244", Light: "#ccd0da"}
	colOverlay0 = lipgloss.AdaptiveColor{Dark: "#6c7086", Light: "#9ca0b0"}
	colText     = lipgloss.AdaptiveColor{Dark: "#cdd6f4", Light: "#4c4f69"}
	colSubtext0 = lipgloss.AdaptiveColor{Dark: "#a6adc8", Light: "#6c6f85"}
	colRed      = lipgloss.AdaptiveColor{Dark: "#f38ba8", Light: "#d20f39"}
	colGreen    = lipgloss.AdaptiveColor{Dark: "#a6e3a1", Light: "#40a02b"}
	colBlue     = lipgloss.AdaptiveColor{Dark: "#89b4fa", Light: "#1e66f5"}
	colLavender = lipgloss.AdaptiveColor{Dark: "#b4befe", Light: "#7287fd"}
	colMauve    = lipgloss.AdaptiveColor{Dark: "#cba6f7", Light: "#8839ef"}
)

// Semantic style variables used across the TUI.
var (
	subtitleStyle = lipgloss.NewStyle().Foreground(colSubtext0)
	dimStyle      = lipgloss.NewStyle().Foreground(colOverlay0)
	keyStyle      = lipgloss.NewStyle().Foreground(colLavender).Bold(true)
	descStyle     = lipgloss.NewStyle().Foreground(colSubtext0)
)

// Styles bundles the shared lipgloss styles derived from a Theme.
// Kept for backward compatibility with sessions.go and other consumers.
type Styles struct {
	App   lipgloss.Style
	Title lipgloss.Style
	Hint  lipgloss.Style
	Error lipgloss.Style
}

// NewStyles builds a Styles from a Theme.
func NewStyles(t Theme) Styles {
	return Styles{
		App:   lipgloss.NewStyle().Foreground(t.Foreground),
		Title: lipgloss.NewStyle().Foreground(t.Accent).Bold(true),
		Hint:  lipgloss.NewStyle().Foreground(t.Muted),
		Error: lipgloss.NewStyle().Foreground(t.Error),
	}
}

package tui

import (
	"fmt"

	"github.com/charmbracelet/bubbles/spinner"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/justincordova/agentlens/internal/parser"
)

type appState int

const (
	stateList appState = iota
	stateLoading
	stateOverview
	stateError
)

// App is the root Bubbletea model. Routes between picker, loading, and overview.
type App struct {
	state    appState
	picker   Picker
	overview Overview
	spinner  spinner.Model
	loading  string
	lastErr  string
	styles   Styles
}

// NewApp returns the root model with a pre-populated session list.
func NewApp(metas []parser.SessionMeta) App {
	sp := spinner.New()
	sp.Spinner = spinner.Dot
	return App{
		state:   stateList,
		picker:  NewPicker(metas),
		spinner: sp,
		styles:  NewStyles(CatppuccinMocha()),
	}
}

func (a App) Init() tea.Cmd { return a.picker.Init() }

func (a App) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch m := msg.(type) {
	case OpenSessionMsg:
		a.state = stateLoading
		a.loading = m.Meta.Path
		return a, tea.Batch(a.spinner.Tick, LoadSessionCmd(m.Meta.Path))
	case SessionLoadedMsg:
		a.overview = NewOverview(m.Session, m.Topics)
		a.state = stateOverview
		return a, nil
	case SessionLoadErrMsg:
		a.state = stateError
		a.lastErr = fmt.Sprintf("load %s: %v", m.Path, m.Err)
		return a, nil
	case ReturnToPickerMsg:
		a.state = stateList
		return a, nil
	case spinner.TickMsg:
		if a.state == stateLoading {
			var cmd tea.Cmd
			a.spinner, cmd = a.spinner.Update(m)
			return a, cmd
		}
		return a, nil
	}

	switch a.state {
	case stateList:
		pm, cmd := a.picker.Update(msg)
		a.picker = pm.(Picker)
		return a, cmd
	case stateOverview:
		om, cmd := a.overview.Update(msg)
		a.overview = om.(Overview)
		return a, cmd
	case stateError:
		if km, ok := msg.(tea.KeyMsg); ok && km.String() == "esc" {
			a.state = stateList
			return a, nil
		}
	}
	return a, nil
}

func (a App) View() string {
	switch a.state {
	case stateLoading:
		return a.styles.App.Render(fmt.Sprintf("%s  parsing %s…\n", a.spinner.View(), a.loading))
	case stateOverview:
		return a.overview.View()
	case stateError:
		return a.styles.App.Render(
			a.styles.Error.Render("error: ") + a.lastErr + "\n\n" +
				a.styles.Hint.Render("press esc to go back"),
		)
	default:
		return a.picker.View()
	}
}

package tui

import (
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"strings"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/dustin/go-humanize"
	"github.com/justincordova/agentlens/internal/parser"
)

// Picker is the Session Picker Bubbletea model. See SPEC §3.1.
type Picker struct {
	metas     []parser.SessionMeta
	cursor    int
	width     int
	height    int
	keys      PickerKeys
	styles    Styles
	confirm   *Confirm
	deleteErr error
}

// NewPicker builds a Picker from pre-scanned metadata.
func NewPicker(metas []parser.SessionMeta) Picker {
	return Picker{
		metas:  metas,
		keys:   DefaultPickerKeys(),
		styles: NewStyles(CatppuccinMocha()),
	}
}

// Cursor returns the current selection index.
func (p Picker) Cursor() int { return p.cursor }

// InConfirm reports whether a confirm modal is currently shown.
func (p Picker) InConfirm() bool { return p.confirm != nil }

// Metas returns the current session list (post-delete).
func (p Picker) Metas() []parser.SessionMeta { return p.metas }

// Selected returns the currently highlighted SessionMeta, or the zero value
// when the list is empty.
func (p Picker) Selected() (parser.SessionMeta, bool) {
	if len(p.metas) == 0 {
		return parser.SessionMeta{}, false
	}
	return p.metas[p.cursor], true
}

// Init satisfies tea.Model.
func (p Picker) Init() tea.Cmd { return nil }

// Update satisfies tea.Model.
func (p Picker) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	if p.confirm != nil {
		if km, ok := msg.(tea.KeyMsg); ok {
			m, _ := p.confirm.Update(km)
			c := m.(Confirm)
			p.confirm = &c
			if c.Done() {
				if c.Confirmed() {
					p.deleteErr = deleteSelected(&p)
				}
				p.confirm = nil
			}
			return p, nil
		}
		return p, nil
	}

	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		p.width = msg.Width
		p.height = msg.Height
		return p, nil
	case tea.KeyMsg:
		switch {
		case key.Matches(msg, p.keys.Quit):
			return p, tea.Quit
		case key.Matches(msg, p.keys.Up):
			if p.cursor > 0 {
				p.cursor--
			}
			return p, nil
		case key.Matches(msg, p.keys.Down):
			if p.cursor < len(p.metas)-1 {
				p.cursor++
			}
			return p, nil
		case key.Matches(msg, p.keys.Open):
			if sel, ok := p.Selected(); ok {
				return p, func() tea.Msg { return OpenSessionMsg{Meta: sel} }
			}
			return p, nil
		case key.Matches(msg, p.keys.Delete):
			if len(p.metas) == 0 {
				return p, nil
			}
			sel := p.metas[p.cursor]
			c := NewConfirm(
				"Delete session?",
				fmt.Sprintf("%s · %s\nThis cannot be undone.", sel.Project, sel.ID),
			)
			p.confirm = &c
			return p, nil
		}
	}
	return p, nil
}

// View satisfies tea.Model.
func (p Picker) View() string {
	if p.confirm != nil {
		return p.confirm.View()
	}
	if len(p.metas) == 0 {
		return p.styles.App.Render(
			p.styles.Title.Render("AgentLens") + "\n\n" +
				p.styles.Hint.Render("No sessions found in ~/.claude/projects/") + "\n\n" +
				p.styles.Hint.Render("press q to quit") + "\n",
		)
	}

	var b strings.Builder
	b.WriteString(p.styles.Title.Render(fmt.Sprintf("Sessions (%d found)", len(p.metas))))
	b.WriteString("\n\n")

	for i, m := range p.metas {
		marker := "  "
		if i == p.cursor {
			marker = "▸ "
		}
		line1 := fmt.Sprintf("%s%-32s  %s  %s",
			marker,
			truncate(m.Project, 32),
			humanizeSize(m.Size),
			humanize.Time(m.ModifiedAt),
		)
		line2 := fmt.Sprintf("    %s · %s", m.Source, backupIndicator(m.HasBackup))
		if i == p.cursor {
			b.WriteString(p.styles.Title.Render(line1))
		} else {
			b.WriteString(line1)
		}
		b.WriteString("\n")
		b.WriteString(p.styles.Hint.Render(line2))
		b.WriteString("\n\n")
	}

	b.WriteString(p.styles.Hint.Render("j/k navigate · enter open · d delete · q quit"))
	b.WriteString("\n")
	return p.styles.App.Render(b.String())
}

// OpenSessionMsg is emitted by the picker when enter is pressed on a session.
type OpenSessionMsg struct {
	Meta parser.SessionMeta
}

// deleteSelected removes the currently-highlighted session's file and
// cleans up its parent directory if it becomes empty.
func deleteSelected(p *Picker) error {
	if len(p.metas) == 0 {
		return nil
	}
	sel := p.metas[p.cursor]
	if err := os.Remove(sel.Path); err != nil {
		slog.Error("delete session failed", "path", sel.Path, "err", err)
		return err
	}
	slog.Info("deleted session", "path", sel.Path)
	dir := filepath.Dir(sel.Path)
	entries, err := os.ReadDir(dir)
	if err == nil && len(entries) == 0 {
		if err := os.Remove(dir); err == nil {
			slog.Info("removed empty project dir", "path", dir)
		}
	}
	p.metas = append(p.metas[:p.cursor], p.metas[p.cursor+1:]...)
	if p.cursor >= len(p.metas) && p.cursor > 0 {
		p.cursor--
	}
	return nil
}

func humanizeSize(n int64) string {
	return humanize.IBytes(uint64(n))
}

func backupIndicator(has bool) string {
	if has {
		return "↶ has backup"
	}
	return ""
}

package tui_test

import (
	"os"
	"path/filepath"
	"testing"
	"time"

	tea "github.com/charmbracelet/bubbletea"
	"github.com/justincordova/agentlens/internal/parser"
	"github.com/justincordova/agentlens/internal/tui"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func fixtures() []parser.SessionMeta {
	return []parser.SessionMeta{
		{ID: "a", Path: "/p/a.jsonl", Project: "proj-a", Source: parser.SourceClaude, ModifiedAt: time.Now().Add(-1 * time.Hour)},
		{ID: "b", Path: "/p/b.jsonl", Project: "proj-b", Source: parser.SourceClaude, ModifiedAt: time.Now().Add(-24 * time.Hour)},
		{ID: "c", Path: "/p/c.jsonl", Project: "proj-c", Source: parser.SourceClaude, ModifiedAt: time.Now().Add(-72 * time.Hour)},
	}
}

func TestPicker_DownKey_MovesCursor(t *testing.T) {
	// Arrange
	m := tui.NewPicker(fixtures())

	// Act
	next, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'j'}})

	// Assert
	p := next.(tui.Picker)
	assert.Equal(t, 1, p.Cursor())
}

func TestPicker_UpKey_AtTopStays(t *testing.T) {
	// Arrange
	m := tui.NewPicker(fixtures())

	// Act
	next, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'k'}})

	// Assert
	p := next.(tui.Picker)
	assert.Equal(t, 0, p.Cursor())
}

func TestPicker_DownKey_AtBottomStays(t *testing.T) {
	// Arrange
	m := tui.NewPicker(fixtures())
	for i := 0; i < 5; i++ {
		m2, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'j'}})
		m = m2.(tui.Picker)
	}

	// Assert — clamped at len-1
	assert.Equal(t, 2, m.Cursor())
}

func TestPicker_QuitKey_EmitsQuitCmd(t *testing.T) {
	// Arrange
	m := tui.NewPicker(fixtures())

	// Act
	_, cmd := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'q'}})

	// Assert
	require.NotNil(t, cmd)
	_, ok := cmd().(tea.QuitMsg)
	assert.True(t, ok)
}

func TestPicker_Empty_ShowsEmptyMessage(t *testing.T) {
	// Arrange
	m := tui.NewPicker(nil)

	// Act
	out := m.View()

	// Assert
	assert.Contains(t, out, "No sessions found")
}

func TestPicker_View_ContainsProjectName(t *testing.T) {
	// Arrange
	m := tui.NewPicker(fixtures())

	// Act
	out := m.View()

	// Assert
	assert.Contains(t, out, "proj-a")
}

func TestPicker_DKey_EntersConfirmState(t *testing.T) {
	// Arrange
	m := tui.NewPicker(fixtures())

	// Act
	next, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'d'}})

	// Assert
	p := next.(tui.Picker)
	assert.True(t, p.InConfirm())
}

func TestPicker_ConfirmN_LeavesConfirmNoDelete(t *testing.T) {
	// Arrange
	m := tui.NewPicker(fixtures())
	m2, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'d'}})
	m = m2.(tui.Picker)

	// Act
	next, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'n'}})

	// Assert
	p := next.(tui.Picker)
	assert.False(t, p.InConfirm())
	assert.Len(t, p.Metas(), 3, "no entries should be removed on cancel")
}

func TestPicker_EnterKey_EmitsOpenSessionMsg(t *testing.T) {
	// Arrange
	m := tui.NewPicker(fixtures())

	// Act
	_, cmd := m.Update(tea.KeyMsg{Type: tea.KeyEnter})

	// Assert
	require.NotNil(t, cmd)
	msg := cmd()
	open, ok := msg.(tui.OpenSessionMsg)
	require.True(t, ok, "expected OpenSessionMsg, got %T", msg)
	assert.Equal(t, "a", open.Meta.ID)
}

func TestPicker_ConfirmY_DeletesFileAndEntry(t *testing.T) {
	// Arrange — real files in a tmp dir
	root := t.TempDir()
	proj := filepath.Join(root, "proj")
	require.NoError(t, os.MkdirAll(proj, 0o755))
	jsonlPath := filepath.Join(proj, "x.jsonl")
	require.NoError(t, os.WriteFile(jsonlPath, []byte(`{"type":"user"}`+"\n"), 0o644))
	m := tui.NewPicker([]parser.SessionMeta{{
		ID:      "x",
		Path:    jsonlPath,
		Project: "proj",
		Source:  parser.SourceClaude,
	}})

	// Act — press d then y
	m2, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'d'}})
	m = m2.(tui.Picker)
	m3, _ := m.Update(tea.KeyMsg{Type: tea.KeyRunes, Runes: []rune{'y'}})
	p := m3.(tui.Picker)

	// Assert
	assert.False(t, p.InConfirm())
	assert.Empty(t, p.Metas())
	_, err := os.Stat(jsonlPath)
	assert.True(t, os.IsNotExist(err), "file should be gone")
	_, err = os.Stat(proj)
	assert.True(t, os.IsNotExist(err), "empty project dir should be cleaned up")
}

