package tui

import (
	"fmt"
	"strings"
	"time"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
	"github.com/dustin/go-humanize"
	"github.com/justincordova/agentlens/internal/parser"
	"github.com/justincordova/agentlens/internal/topics"
)

// Overview is the Topic Overview Bubbletea model per SPEC §3.2.
type Overview struct {
	sess     *parser.Session
	topics   []topics.Topic
	cursor   int
	offset   int
	expanded map[int]bool
	stats    bool
	width    int
	height   int
	keys     OverviewKeys
	styles   Styles
}

// NewOverview constructs the screen from a parsed session and its topics.
func NewOverview(sess *parser.Session, tops []topics.Topic) Overview {
	return Overview{
		sess:     sess,
		topics:   tops,
		expanded: map[int]bool{},
		keys:     DefaultOverviewKeys(),
		styles:   NewStyles(CatppuccinMocha()),
	}
}

func (o Overview) Cursor() int         { return o.cursor }
func (o Overview) Expanded(i int) bool { return o.expanded[i] }
func (o Overview) StatsVisible() bool  { return o.stats }
func (o Overview) Init() tea.Cmd       { return nil }

func (o Overview) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		o.width = msg.Width
		o.height = msg.Height
		return o, nil
	case tea.KeyMsg:
		switch {
		case key.Matches(msg, o.keys.Quit):
			return o, tea.Quit
		case key.Matches(msg, o.keys.Up):
			if o.cursor > 0 {
				o.cursor--
				o.offset = clampOffset(o.cursor, o.offset, len(o.topics), o.topicVisibleCount())
			}
			return o, nil
		case key.Matches(msg, o.keys.Down):
			if o.cursor < len(o.topics)-1 {
				o.cursor++
				o.offset = clampOffset(o.cursor, o.offset, len(o.topics), o.topicVisibleCount())
			}
			return o, nil
		case key.Matches(msg, o.keys.Expand):
			o.expanded[o.cursor] = !o.expanded[o.cursor]
			return o, nil
		case key.Matches(msg, o.keys.Stats):
			o.stats = !o.stats
			return o, nil
		case key.Matches(msg, o.keys.Back):
			return o, func() tea.Msg { return ReturnToPickerMsg{} }
		case key.Matches(msg, o.keys.Replay):
			return o, nil
		case key.Matches(msg, o.keys.Edit):
			return o, nil
		}
	}
	return o, nil
}

func (o Overview) topicVisibleCount() int {
	if o.height <= 0 {
		return 8
	}
	// header(1) + stats(1) + box chrome(3) + footer(1) = 6
	avail := o.height - 6
	cards := avail / 3
	if cards < 1 {
		return 1
	}
	return cards
}

func (o Overview) View() string {
	header := o.renderHeader()
	statsStrip := o.renderStatsStrip()
	footer := o.renderFooter()

	fixedH := lipgloss.Height(header) + lipgloss.Height(statsStrip) + lipgloss.Height(footer)
	mainH := o.height - fixedH
	if mainH < 6 {
		mainH = 6
	}
	main := o.renderTopicPanel(mainH)

	return lipgloss.JoinVertical(lipgloss.Left, header, statsStrip, main, footer)
}

func (o Overview) renderHeader() string {
	logo := renderLogo()

	right := dimStyle.Render("esc ") + keyStyle.Render("back")

	gap := o.width - lipgloss.Width(logo) - lipgloss.Width(right) - 2
	if gap < 1 {
		gap = 1
	}
	row := logo + strings.Repeat(" ", gap) + right
	return lipgloss.NewStyle().Width(o.width).Padding(0, 1).Render(row)
}

func (o Overview) renderStatsStrip() string {
	s := o.sess

	dur := s.ModifiedAt.Sub(s.CreatedAt).Round(time.Minute)
	if dur == 0 {
		dur = s.ModifiedAt.Sub(s.CreatedAt).Round(time.Second)
		if dur == 0 {
			dur = time.Second
		}
	}

	pct := 0.0
	if defaultContextWindow > 0 {
		pct = 100.0 * float64(s.TokenCount) / float64(defaultContextWindow)
	}

	tokenColor := colGreen
	if pct > 80 {
		tokenColor = colRed
	} else if pct > 50 {
		tokenColor = colLavender
	}

	items := []string{
		statInline("TURNS", fmt.Sprintf("%d", len(s.Turns)), colGreen),
		statInline("TOKENS", fmt.Sprintf("~%s (%.0f%%)", humanize.Comma(int64(s.TokenCount)), pct), tokenColor),
		statInline("TOPICS", fmt.Sprintf("%d", len(o.topics)), colMauve),
		statInline("DURATION", dur.String(), colLavender),
	}

	sep := dimStyle.Render("  │  ")
	row := strings.Join(items, sep)
	return lipgloss.NewStyle().Width(o.width).Padding(0, 2).Render(row)
}

func (o Overview) renderTopicPanel(height int) string {
	title := fmt.Sprintf(" %s %s %s",
		lipgloss.NewStyle().Foreground(colText).Bold(true).Render(string(o.sess.Source)),
		dimStyle.Render("·"),
		dimStyle.Render(shortID(o.sess.ID)),
	)
	body := o.renderTopicList(o.width-4, height-4)
	return panel(title, body, o.width, height)
}

func (o Overview) renderTopicList(width, maxLines int) string {
	var b strings.Builder
	visible := maxLines / 3
	if visible < 1 {
		visible = 1
	}

	end := o.offset + visible
	if end > len(o.topics) {
		end = len(o.topics)
	}
	for i := o.offset; i < end; i++ {
		top := o.topics[i]
		b.WriteString(o.renderTopicCard(i, top, width))
		if o.expanded[i] {
			renderExpanded(&b, o.styles, o.sess, top)
		}
		if i < end-1 {
			b.WriteString("\n")
		}
	}
	return b.String()
}

func (o Overview) renderTopicCard(i int, top topics.Topic, width int) string {
	selected := i == o.cursor

	barStyle := lipgloss.NewStyle().Foreground(colSurface1)
	if selected {
		barStyle = lipgloss.NewStyle().Foreground(colMauve).Bold(true)
	}
	bar := barStyle.Render("▌")

	label := textStyle.Render(truncate(top.Label, 40))
	if selected {
		label = lipgloss.NewStyle().Foreground(colText).Bold(true).Render(truncate(top.Label, 40))
	}

	num := dimStyle.Render(fmt.Sprintf("%2d.", i+1))
	tokenBar := TokenBar(top.TokenCount, o.sess.TokenCount, 8)
	tokens := dimStyle.Render(fmt.Sprintf("~%s", humanize.Comma(int64(top.TokenCount))))

	line1 := fmt.Sprintf("%s %s %-40s  %s  %s", bar, num, label, tokenBar, tokens)

	durMin := int(top.Duration.Minutes())
	turnRange := dimStyle.Render(fmt.Sprintf("turns %d–%d",
		firstTurnIdx(top.TurnIndices)+1,
		lastTurnIdx(top.TurnIndices)+1))
	toolCalls := dimStyle.Render(fmt.Sprintf("%d tool calls", top.ToolCallCount))
	duration := dimStyle.Render(fmt.Sprintf("%d min", durMin))
	line2 := fmt.Sprintf("       %s · %s · %s", turnRange, toolCalls, duration)

	return lipgloss.JoinVertical(lipgloss.Left, line1, line2)
}

func (o Overview) renderFooter() string {
	hints := joinHints(
		kbd("↑↓/jk", "nav"),
		kbd("enter", "expand"),
		kbd("tab", "stats"),
		kbd("esc", "back"),
		kbd("q", "quit"),
	)
	hintsW := lipgloss.Width(hints)
	gap := (o.width - hintsW) / 2
	if gap < 2 {
		gap = 2
	}
	return lipgloss.NewStyle().Width(o.width).Render(strings.Repeat(" ", gap) + hints)
}

// ReturnToPickerMsg tells the root app to swap back to the session picker.
type ReturnToPickerMsg struct{}

func shortID(id string) string {
	if len(id) > 12 {
		return id[:12]
	}
	return id
}

// TokenBar renders an 8-cell block-char progress bar: █ filled, ░ empty.
func TokenBar(tokens, total, width int) string {
	if width <= 0 {
		return ""
	}
	filled := 0
	if total > 0 {
		filled = int(float64(tokens) / float64(total) * float64(width))
		if filled > width {
			filled = width
		}
	}
	return strings.Repeat("█", filled) + strings.Repeat("░", width-filled)
}

func firstTurnIdx(ix []int) int {
	if len(ix) == 0 {
		return 0
	}
	return ix[0]
}

func lastTurnIdx(ix []int) int {
	if len(ix) == 0 {
		return 0
	}
	return ix[len(ix)-1]
}

func renderExpanded(b *strings.Builder, st Styles, sess *parser.Session, top topics.Topic) {
	for _, ix := range top.TurnIndices {
		if ix < 0 || ix >= len(sess.Turns) {
			continue
		}
		tn := sess.Turns[ix]
		badge := roleBadge(tn.Role)
		preview := truncate(firstLine(tn.Content), 60)
		line := fmt.Sprintf("       %s  %-60s  ~%d", badge, preview, tn.Tokens)
		b.WriteString(st.Hint.Render(line))
		b.WriteString("\n")
	}
	b.WriteString("\n")
}

func roleBadge(r parser.Role) string {
	switch r {
	case parser.RoleUser:
		return pill("USER", colBase, colGreen)
	case parser.RoleAssistant:
		return pill("ASST", colBase, colBlue)
	case parser.RoleToolResult:
		return pill("TOOL", colBase, colLavender)
	default:
		return pill(strings.ToUpper(string(r)), colBase, colOverlay0)
	}
}

func firstLine(s string) string {
	for _, ln := range strings.Split(s, "\n") {
		if t := strings.TrimSpace(ln); t != "" {
			return t
		}
	}
	return ""
}

const defaultContextWindow = 200_000

func renderStats(st Styles, sess *parser.Session, tops []topics.Topic) string {
	roleCounts := map[parser.Role]int{}
	roleTokens := map[parser.Role]int{}
	fileSet := map[string]struct{}{}
	var tools int
	for _, tn := range sess.Turns {
		roleCounts[tn.Role]++
		roleTokens[tn.Role] += tn.Tokens
		tools += len(tn.ToolCalls)
	}
	for _, top := range tops {
		for _, f := range top.FileSet {
			fileSet[f] = struct{}{}
		}
	}
	dur := sess.ModifiedAt.Sub(sess.CreatedAt).Round(time.Minute)
	if dur == 0 {
		dur = sess.ModifiedAt.Sub(sess.CreatedAt).Round(time.Second)
		if dur == 0 {
			dur = time.Second
		}
	}
	pct := 0.0
	if defaultContextWindow > 0 {
		pct = 100.0 * float64(sess.TokenCount) / float64(defaultContextWindow)
	}
	lines := []string{
		"── stats ──",
		fmt.Sprintf("total: ~%s tokens (%.1f%% of %s ctx)",
			humanize.Comma(int64(sess.TokenCount)), pct, humanize.Comma(int64(defaultContextWindow))),
		fmt.Sprintf("user: %d turns / ~%s tok",
			roleCounts[parser.RoleUser], humanize.Comma(int64(roleTokens[parser.RoleUser]))),
		fmt.Sprintf("assistant: %d turns / ~%s tok",
			roleCounts[parser.RoleAssistant], humanize.Comma(int64(roleTokens[parser.RoleAssistant]))),
		fmt.Sprintf("tool calls: %d · tool results: %d", tools, roleCounts[parser.RoleToolResult]),
		fmt.Sprintf("%s · %s session · %d topic files",
			countLabel(len(tops), "topic"), dur, len(fileSet)),
	}
	return st.Hint.Render(strings.Join(lines, "\n"))
}

package tui

import (
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"strings"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
	"github.com/dustin/go-humanize"
	"github.com/justincordova/agentlens/internal/parser"
)

// Picker is the Session Picker Bubbletea model. See SPEC §3.1.
type Picker struct {
	metas     []parser.SessionMeta
	cursor    int
	offset    int
	width     int
	height    int
	keys      PickerKeys
	styles    Styles
	confirm   *Confirm
	deleteErr error
}

// NewPicker builds a Picker from pre-scanned metadata.
func NewPicker(metas []parser.SessionMeta) Picker {
	return Picker{
		metas:  metas,
		keys:   DefaultPickerKeys(),
		styles: NewStyles(CatppuccinMocha()),
	}
}

// Cursor returns the current selection index.
func (p Picker) Cursor() int { return p.cursor }

// InConfirm reports whether a confirm modal is currently shown.
func (p Picker) InConfirm() bool { return p.confirm != nil }

// Metas returns the current session list (post-delete).
func (p Picker) Metas() []parser.SessionMeta { return p.metas }

// Selected returns the currently highlighted SessionMeta, or the zero value
// when the list is empty.
func (p Picker) Selected() (parser.SessionMeta, bool) {
	if len(p.metas) == 0 {
		return parser.SessionMeta{}, false
	}
	return p.metas[p.cursor], true
}

// Init satisfies tea.Model.
func (p Picker) Init() tea.Cmd { return nil }

// Update satisfies tea.Model.
func (p Picker) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	if p.confirm != nil {
		if km, ok := msg.(tea.KeyMsg); ok {
			m, _ := p.confirm.Update(km)
			c := m.(Confirm)
			p.confirm = &c
			if c.Done() {
				if c.Confirmed() {
					p.deleteErr = deleteSelected(&p)
				}
				p.confirm = nil
			}
			return p, nil
		}
		return p, nil
	}

	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		p.width = msg.Width
		p.height = msg.Height
		return p, nil
	case tea.KeyMsg:
		switch {
		case key.Matches(msg, p.keys.Quit):
			return p, tea.Quit
		case key.Matches(msg, p.keys.Up):
			if p.cursor > 0 {
				p.cursor--
				p.offset = clampOffset(p.cursor, p.offset, len(p.metas), p.visibleCount())
			}
			return p, nil
		case key.Matches(msg, p.keys.Down):
			if p.cursor < len(p.metas)-1 {
				p.cursor++
				p.offset = clampOffset(p.cursor, p.offset, len(p.metas), p.visibleCount())
			}
			return p, nil
		case key.Matches(msg, p.keys.Open):
			if sel, ok := p.Selected(); ok {
				return p, func() tea.Msg { return OpenSessionMsg{Meta: sel} }
			}
			return p, nil
		case key.Matches(msg, p.keys.Delete):
			if len(p.metas) == 0 {
				return p, nil
			}
			sel := p.metas[p.cursor]
			c := NewConfirm(
				"Delete session?",
				fmt.Sprintf("%s · %s\nThis cannot be undone.", sel.Project, sel.ID),
			)
			p.confirm = &c
			return p, nil
		}
	}
	return p, nil
}

// View satisfies tea.Model.
func (p Picker) View() string {
	if p.confirm != nil {
		return p.confirm.View()
	}

	header := p.renderHeader()
	statsStrip := p.renderStats()
	footer := p.renderFooter()

	fixedH := lipgloss.Height(header) + lipgloss.Height(statsStrip) + lipgloss.Height(footer)
	mainH := p.height - fixedH
	if mainH < 6 {
		mainH = 6
	}
	main := p.renderSessionPanel(mainH)

	return lipgloss.JoinVertical(lipgloss.Left, header, statsStrip, main, footer)
}

func renderLogo() string {
	text := "◆ AgentLens"
	gradient := []lipgloss.TerminalColor{colMauve, colMauve, colLavender, colPink, colPink, colFlamingo, colFlamingo, colPink, colPink, colLavender, colMauve}
	var b strings.Builder
	for i, r := range text {
		color := gradient[i%len(gradient)]
		b.WriteString(lipgloss.NewStyle().Foreground(color).Bold(true).Render(string(r)))
	}
	return b.String()
}

func (p Picker) renderHeader() string {
	logo := renderLogo()
	ver := dimStyle.Render("v0.1")
	left := logo + " " + ver

	right := joinHints(
		kbd("?", "help"),
	)

	gap := p.width - lipgloss.Width(left) - lipgloss.Width(right) - 2
	if gap < 1 {
		gap = 1
	}
	row := left + strings.Repeat(" ", gap) + right
	return lipgloss.NewStyle().Width(p.width).Padding(0, 1).Render(row)
}

func (p Picker) renderStats() string {
	var totalTokens int64
	var totalSize int64
	for _, m := range p.metas {
		totalSize += m.Size
	}

	sessVal := fmt.Sprintf("%d", len(p.metas))
	sizeVal := humanizeSize(totalSize)
	tokenVal := "—"
	if totalTokens > 0 {
		tokenVal = humanize.Comma(totalTokens)
	}

	items := []string{
		statInline("SESSIONS", sessVal, colGreen),
		statInline("TOTAL SIZE", sizeVal, colLavender),
		statInline("SOURCE", "Claude Code", colMauve),
	}
	_ = tokenVal

	sep := dimStyle.Render("  │  ")
	row := strings.Join(items, sep)
	return lipgloss.NewStyle().Width(p.width).Padding(0, 2).Render(row)
}

func statInline(label, value string, valueColor lipgloss.TerminalColor) string {
	l := lipgloss.NewStyle().Foreground(colOverlay1).Bold(true).Render(label)
	v := lipgloss.NewStyle().Foreground(valueColor).Bold(true).Render(value)
	return l + " " + v
}

func (p Picker) renderSessionPanel(height int) string {
	if len(p.metas) == 0 {
		body := "\n" + textStyle.Render("No sessions found.") + "\n\n" +
			dimStyle.Render("Place session JSONL files in ~/.claude/projects/")
		title := " Sessions"
		return panel(title, body, p.width, height)
	}

	title := fmt.Sprintf(" Sessions %s", dimStyle.Render(fmt.Sprintf("(%d)", len(p.metas))))
	body := p.renderSessionList(p.width-4, height-4)
	return panel(title, body, p.width, height)
}

func panel(title, body string, width, height int) string {
	style := boxStyle.Width(width - 2).Height(height - 2)
	titleBar := ""
	if title != "" {
		titleBar = lipgloss.NewStyle().Foreground(colMauve).Bold(true).Render(title) + "\n"
	}
	return style.Render(titleBar + body)
}

func (p Picker) renderSessionList(width, maxLines int) string {
	var b strings.Builder
	visible := maxLines / 3
	if visible < 1 {
		visible = 1
	}

	end := p.offset + visible
	if end > len(p.metas) {
		end = len(p.metas)
	}
	for i := p.offset; i < end; i++ {
		b.WriteString(p.renderSessionCard(i, width))
		if i < end-1 {
			b.WriteString("\n")
		}
	}
	return b.String()
}

func (p Picker) renderSessionCard(i, width int) string {
	m := p.metas[i]
	selected := i == p.cursor

	barStyle := lipgloss.NewStyle().Foreground(colSurface1)
	if selected {
		barStyle = lipgloss.NewStyle().Foreground(colMauve).Bold(true)
	}
	bar := barStyle.Render("▌")

	name := textStyle.Render(truncate(m.Project, 40))
	if selected {
		name = lipgloss.NewStyle().Foreground(colText).Bold(true).Render(truncate(m.Project, 40))
	}

	size := dimStyle.Render(humanizeSize(m.Size))
	age := dimStyle.Render(humanize.Time(m.ModifiedAt))

	line1Gap := width - lipgloss.Width(name) - lipgloss.Width(size) - lipgloss.Width(age) - 6
	if line1Gap < 1 {
		line1Gap = 1
	}
	line1 := bar + " " + name + strings.Repeat(" ", line1Gap) + size + "  " + age

	src := dimStyle.Render(string(m.Source))
	backup := ""
	if m.HasBackup {
		backup = dimStyle.Render(" · ") + successStyle.Render("↶ backup")
	}
	line2 := bar + "  " + src + backup

	return lipgloss.JoinVertical(lipgloss.Left, line1, line2)
}

func (p Picker) renderFooter() string {
	hints := joinHints(
		kbd("↑↓/jk", "nav"),
		kbd("enter", "open"),
		kbd("d", "delete"),
		kbd("q", "quit"),
	)
	hintsW := lipgloss.Width(hints)
	gap := (p.width - hintsW) / 2
	if gap < 2 {
		gap = 2
	}
	return lipgloss.NewStyle().Width(p.width).Render(strings.Repeat(" ", gap) + hints)
}

func (p Picker) visibleCount() int {
	if p.height <= 0 {
		return 8
	}
	// header(1) + stats(1) + box border/title(3) + footer(1) = ~6 lines of chrome
	avail := p.height - 6
	cards := avail / 3 // 3 lines per card (line1, line2, gap)
	if cards < 1 {
		return 1
	}
	return cards
}

// clampOffset adjusts offset so that cursor is within [offset, offset+visible).
// Scrolls only when the cursor moves past the top or bottom edge.
func clampOffset(cursor, offset, total, visible int) int {
	if total <= visible {
		return 0
	}
	if cursor < offset {
		offset = cursor
	}
	if cursor >= offset+visible {
		offset = cursor - visible + 1
	}
	if offset+visible > total {
		offset = total - visible
	}
	if offset < 0 {
		offset = 0
	}
	return offset
}

// OpenSessionMsg is emitted by the picker when enter is pressed on a session.
type OpenSessionMsg struct {
	Meta parser.SessionMeta
}

// deleteSelected removes the currently-highlighted session's file and
// cleans up its parent directory if it becomes empty.
func deleteSelected(p *Picker) error {
	if len(p.metas) == 0 {
		return nil
	}
	sel := p.metas[p.cursor]
	if err := os.Remove(sel.Path); err != nil {
		slog.Error("delete session failed", "path", sel.Path, "err", err)
		return err
	}
	slog.Info("deleted session", "path", sel.Path)
	dir := filepath.Dir(sel.Path)
	entries, err := os.ReadDir(dir)
	if err == nil && len(entries) == 0 {
		if rmErr := os.Remove(dir); rmErr == nil {
			slog.Info("removed empty project dir", "path", dir)
		} else {
			slog.Warn("could not remove empty project dir", "path", dir, "err", rmErr)
		}
	}
	p.metas = append(p.metas[:p.cursor], p.metas[p.cursor+1:]...)
	if p.cursor >= len(p.metas) && p.cursor > 0 {
		p.cursor--
	}
	return nil
}

func humanizeSize(n int64) string {
	return humanize.IBytes(uint64(n))
}

