		})
	}
}

func TestPadRight(t *testing.T) {
	cases := []struct {
		name  string
		input string
		width int
		want  string
	}{
		{name: "shorter than width", input: "ab", width: 5, want: "ab   "},
		{name: "exact width", input: "abc", width: 3, want: "abc"},
		{name: "longer than width", input: "abcde", width: 3, want: "abcde"},
