1	package tui
2	
3	import (
4		"fmt"
5		"sort"
6		"strings"
7		"time"
8	
9		"github.com/charmbracelet/bubbles/key"
10		tea "github.com/charmbracelet/bubbletea"
11		"github.com/charmbracelet/lipgloss"
12		"github.com/dustin/go-humanize"
13		"github.com/justincordova/agentlens/internal/parser"
14		"github.com/justincordova/agentlens/internal/topics"
15	)
16	
17	// Overview is the Topic Overview Bubbletea model per SPEC §3.2.
18	type Overview struct {
19		sess     *parser.Session
20		topics   []topics.Topic
21		cursor   int
22		offset   int
23		expanded map[int]bool
24		stats    bool
25		width    int
26		height   int
27		keys     OverviewKeys
28		styles   Styles
29	}
30	
31	// NewOverview constructs the screen from a parsed session and its topics.
32	// Topics are displayed latest-first (by first-turn timestamp descending).
33	func NewOverview(sess *parser.Session, tops []topics.Topic) Overview {
34		sorted := make([]topics.Topic, len(tops))
35		copy(sorted, tops)
36		sort.SliceStable(sorted, func(i, j int) bool {
37			return topicStartTime(sess, sorted[i]).After(topicStartTime(sess, sorted[j]))
38		})
39		return Overview{
40			sess:     sess,
41			topics:   sorted,
42			expanded: map[int]bool{},
43			keys:     DefaultOverviewKeys(),
44			styles:   NewStyles(CatppuccinMocha()),
45		}
46	}
47	
48	func topicStartTime(sess *parser.Session, top topics.Topic) time.Time {
49		if sess == nil || len(top.TurnIndices) == 0 {
50			return time.Time{}
51		}
52		ix := top.TurnIndices[0]
53		if ix < 0 || ix >= len(sess.Turns) {
54			return time.Time{}
55		}
56		return sess.Turns[ix].Timestamp
57	}
58	
59	func (o Overview) Cursor() int         { return o.cursor }
60	func (o Overview) Expanded(i int) bool { return o.expanded[i] }
61	func (o Overview) StatsVisible() bool  { return o.stats }
62	func (o Overview) Init() tea.Cmd       { return nil }
63	
64	func (o Overview) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
65		switch msg := msg.(type) {
66		case tea.WindowSizeMsg:
67			o.width = msg.Width
68			o.height = msg.Height
69			return o, nil
70		case tea.KeyMsg:
71			switch {
72			case key.Matches(msg, o.keys.Quit):
73				return o, tea.Quit
74			case key.Matches(msg, o.keys.Up):
75				if o.cursor > 0 {
76					o.cursor--
77					o.offset = clampOffset(o.cursor, o.offset, len(o.topics), o.topicVisibleCount())
78				}
79				return o, nil
80			case key.Matches(msg, o.keys.Down):
81				if o.cursor < len(o.topics)-1 {
82					o.cursor++
83					o.offset = clampOffset(o.cursor, o.offset, len(o.topics), o.topicVisibleCount())
84				}
85				return o, nil
86			case key.Matches(msg, o.keys.Expand):
87				o.expanded[o.cursor] = !o.expanded[o.cursor]
88				return o, nil
89			case key.Matches(msg, o.keys.Stats):
90				o.stats = !o.stats
91				return o, nil
92			case key.Matches(msg, o.keys.Back):
93				return o, func() tea.Msg { return ReturnToPickerMsg{} }
94			case key.Matches(msg, o.keys.Replay):
95				return o, nil
96			case key.Matches(msg, o.keys.Edit):
97				return o, nil
98			}
99		}
100		return o, nil
101	}
102	
103	func (o Overview) topicVisibleCount() int {
104		if o.height <= 0 {
105			return 8
106		}
107		// header(1) + stats(1) + box chrome(3) + footer(1) = 6
108		avail := o.height - 6
109		cards := avail / 2 // each card renders as 2 tight lines
110		if cards < 1 {
111			return 1
112		}
113		return cards
114	}
115	
116	func (o Overview) View() string {
117		header := o.renderHeader()
118		statsStrip := o.renderStatsStrip()
119		footer := o.renderFooter()
120	
121		fixedH := lipgloss.Height(header) + lipgloss.Height(statsStrip) + lipgloss.Height(footer)
122		mainH := o.height - fixedH
123		if mainH < 6 {
124			mainH = 6
125		}
126		var main string
127		if o.stats {
128			main = o.renderStatsPanel(mainH)
129		} else {
130			main = o.renderTopicPanel(mainH)
131		}
132	
133		return lipgloss.JoinVertical(lipgloss.Left, header, statsStrip, main, footer)
134	}
135	
136	func (o Overview) renderStatsPanel(height int) string {
137		title := fmt.Sprintf(" Stats %s", dimStyle.Render("(tab to return)"))
138		body := renderStats(o.styles, o.sess, o.topics)
139		return panel(title, body, o.width, height)
140	}
141	
142	func (o Overview) renderHeader() string {
143		logo := renderLogo()
144	
145		right := dimStyle.Render("esc ") + keyStyle.Render("back")
146	
147		gap := o.width - lipgloss.Width(logo) - lipgloss.Width(right) - 2
148		if gap < 1 {
149			gap = 1
150		}
151		row := logo + strings.Repeat(" ", gap) + right
152		return lipgloss.NewStyle().Width(o.width).Padding(0, 1).Render(row)
153	}
154	
155	func (o Overview) renderStatsStrip() string {
156		s := o.sess
157	
158		dur := s.ModifiedAt.Sub(s.CreatedAt).Round(time.Minute)
159		if dur == 0 {
160			dur = s.ModifiedAt.Sub(s.CreatedAt).Round(time.Second)
161			if dur == 0 {
162				dur = time.Second
163			}
164		}
165	
166		pct := 0.0
167		if defaultContextWindow > 0 {
168			pct = 100.0 * float64(s.TokenCount) / float64(defaultContextWindow)
169		}
170	
171		tokenColor := colGreen
172		if pct > 80 {
173			tokenColor = colRed
174		} else if pct > 50 {
175			tokenColor = colLavender
176		}
177	
178		items := []string{
179			statInline("TURNS", fmt.Sprintf("%d", len(s.Turns)), colGreen),
180			statInline("TOKENS", fmt.Sprintf("~%s (%.0f%%)", humanize.Comma(int64(s.TokenCount)), pct), tokenColor),
181			statInline("TOPICS", fmt.Sprintf("%d", len(o.topics)), colMauve),
182			statInline("DURATION", dur.String(), colLavender),
183		}
184	
185		sep := dimStyle.Render("  │  ")
186		row := strings.Join(items, sep)
187		return lipgloss.NewStyle().Width(o.width).Padding(0, 2).Render(row)
188	}
189	
190	func (o Overview) renderTopicPanel(height int) string {
191		title := fmt.Sprintf(" %s %s %s",
192			lipgloss.NewStyle().Foreground(colText).Bold(true).Render(string(o.sess.Source)),
193			dimStyle.Render("·"),
194			dimStyle.Render(shortID(o.sess.ID)),
195		)
196		body := o.renderTopicList(o.width-4, height-4)
197		return panel(title, body, o.width, height)
198	}
199	
200	func (o Overview) renderTopicList(width, maxLines int) string {
201		var b strings.Builder
202		visible := maxLines / 2 // each card renders as 2 tight lines
203		if visible < 1 {
204			visible = 1
205		}
206	
207		end := o.offset + visible
208		if end > len(o.topics) {
209			end = len(o.topics)
210		}
211		for i := o.offset; i < end; i++ {
212			top := o.topics[i]
213			b.WriteString(o.renderTopicCard(i, top, width))
214			if o.expanded[i] {
215				renderExpanded(&b, o.styles, o.sess, top)
216			}
217			if i < end-1 {
218				b.WriteString("\n")
219			}
220		}
221		return b.String()
222	}
223	
224	func (o Overview) renderTopicCard(i int, top topics.Topic, width int) string {
225		selected := i == o.cursor
226	
227		barStyle := lipgloss.NewStyle().Foreground(colSurface1)
228		if selected {
229			barStyle = lipgloss.NewStyle().Foreground(colMauve).Bold(true)
230		}
231		bar := barStyle.Render("▌")
232	
233		label := textStyle.Render(truncate(top.Label, 40))
234		if selected {
235			label = lipgloss.NewStyle().Foreground(colText).Bold(true).Render(truncate(top.Label, 40))
236		}
237	
238		num := dimStyle.Render(fmt.Sprintf("%2d.", i+1))
239		tokenBar := TokenBar(top.TokenCount, o.sess.TokenCount, 8)
240		tokens := dimStyle.Render(fmt.Sprintf("~%s", humanize.Comma(int64(top.TokenCount))))
241	
242		line1 := fmt.Sprintf("%s %s %-40s  %s  %s", bar, num, label, tokenBar, tokens)
243	
244		durMin := int(top.Duration.Minutes())
245		turnRange := dimStyle.Render(fmt.Sprintf("turns %d–%d",
246			firstTurnIdx(top.TurnIndices)+1,
247			lastTurnIdx(top.TurnIndices)+1))
248		toolCalls := dimStyle.Render(fmt.Sprintf("%d tool calls", top.ToolCallCount))
249		duration := dimStyle.Render(fmt.Sprintf("%d min", durMin))
250		parts := []string{turnRange, toolCalls, duration}
251		if ts := topicStartTime(o.sess, top); !ts.IsZero() {
252			parts = append(parts, dimStyle.Render(humanize.Time(ts)))
253		}
254		line2 := "       " + strings.Join(parts, dimStyle.Render(" · "))
255	
256		return lipgloss.JoinVertical(lipgloss.Left, line1, line2)
257	}
258	
259	func (o Overview) renderFooter() string {
260		hints := joinHints(
261			kbd("↑↓/jk", "nav"),
262			kbd("enter", "expand"),
263			kbd("tab", "stats"),
264			kbd("esc", "back"),
265			kbd("q", "quit"),
266		)
267		hintsW := lipgloss.Width(hints)
268		gap := (o.width - hintsW) / 2
269		if gap < 2 {
270			gap = 2
271		}
272		return lipgloss.NewStyle().Width(o.width).Render(strings.Repeat(" ", gap) + hints)
273	}
274	
275	// ReturnToPickerMsg tells the root app to swap back to the session picker.
276	type ReturnToPickerMsg struct{}
277	
278	func shortID(id string) string {
279		if len(id) > 12 {
280			return id[:12]
281		}
282		return id
283	}
284	
285	// TokenBar renders an 8-cell block-char progress bar: █ filled, ░ empty.
286	func TokenBar(tokens, total, width int) string {
287		if width <= 0 {
288			return ""
289		}
290		filled := 0
291		if total > 0 {
292			filled = int(float64(tokens) / float64(total) * float64(width))
293			if filled > width {
294				filled = width
295			}
296		}
297		return strings.Repeat("█", filled) + strings.Repeat("░", width-filled)
298	}
299	
300	func firstTurnIdx(ix []int) int {
301		if len(ix) == 0 {
302			return 0
303		}
304		return ix[0]
305	}
306	
307	func lastTurnIdx(ix []int) int {
308		if len(ix) == 0 {
309			return 0
310		}
311		return ix[len(ix)-1]
312	}
