}

func (o Overview) renderTopicList(width, maxLines int) string {
	var b strings.Builder
	visible := maxLines / 2 // each card renders as 2 tight lines
	if visible < 1 {
		visible = 1
	}

	end := o.offset + visible
	if end > len(o.topics) {
		end = len(o.topics)
	}
	for i := o.offset; i < end; i++ {
		top := o.topics[i]
		b.WriteString(o.renderTopicCard(i, top, width))
		if o.expanded[i] {
			renderExpanded(&b, o.styles, o.sess, top)
		}
		if i < end-1 {
			b.WriteString("\n")
		}
	}
	return b.String()
}

