}

func (p Picker) visibleCount() int {
	if p.height <= 0 {
		return 8
	}
	// header(1) + stats(1) + box border/title(3) + footer(1) = ~6 lines of chrome
	avail := p.height - 6
	cards := avail / 3 // 3 lines per card (line1, line2, gap)
	if cards < 1 {
		return 1
	}
	return cards
}

// clampOffset adjusts offset so that cursor is within [offset, offset+visible).
// Scrolls only when the cursor moves past the top or bottom edge.
func clampOffset(cursor, offset, total, visible int) int {
	if total <= visible {
		return 0
	}
	if cursor < offset {
		offset = cursor
	}
	if cursor >= offset+visible {
		offset = cursor - visible + 1
	}
	if offset+visible > total {
